Rule.Source:
  import sailpoint.object.ResourceObject;
  import sailpoint.tools.Util;
  import sailpoint.api.ObjectUtil;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;
  
  Log logger = LogFactory.getLog("Ascension-Rule-ResourceObject-Customization-ServiceNow");
  logger.debug("Start Ascension-Rule-ResourceObject-Customization-ServiceNow");


  //u_termdate
  Object termDateObj = object.getAttribute("u_termdate");
  if(termDateObj != null ){
    if(Util.isNotNullOrEmpty(termDateObj) ){
      object.put("IIQDisabled", true);
      object.put("active", false);		
    }else{
      object.put("IIQDisabled", false); 
      object.put("active", true);
    }
  }else{
    object.put("IIQDisabled", false);
    object.put("active", true);
  }
  logger.debug("End Ascension-Rule-ResourceObject-Customization-ServiceNow");

  return object;
